, "grok_analysis_button": true, "is_translatable": false, "legacy": {"bookmark_count": 675, "bookmarked": false, "conversation_id_str": "2003593613918531891", "created_at": "Tue Dec 23 22:28:37 +0000 2025", "display_text_range": [0, 276], "entities": {"hashtags": [], "symbols": [], "timestamps": [], "urls": [], "user_mentions": []}, "favorite_count": 7813, "favorited": false, "full_text": "I was very late to own a Tesla but among the earliest to try out FSD v14.  It's perhaps the first time I experience an AI that passes the Physical Turing Test: after a long day at work, you press a button, lay back, and couldn't tell if a neural net or a human drove you home.", "id_str": "2003593613918531891", "is_quote_status": true, "lang": "en", "quote_count": 155, "quoted_status_id_str": "2002843697273262468", "quoted_status_permalink": {"display": "x.com/philduan/statu…", "expanded": "https://twitter.com/philduan/status/2002843697273262468", "url": "https://t.co/PDOn6ZFTZA"}, "reply_count": 397, "retweet_count": 1324, "retweeted": false, "user_id_str": "1007413134"}, "note_tweet": {"is_expandable": true, "note_tweet_results": {"result": {"entity_set": {"hashtags": [], "symbols": [], "urls": [], "user_mentions": []}, "id": "Tm90ZVR3ZWV0OjIwMDM1OTM2MTM4MDExMjc5MzY=", "media": {"inline_media": []}, "richtext": {"richtext_tags": []}, "text": "I was very late to own a Tesla but among the earliest to try out FSD v14.  It's perhaps the first time I experience an AI that passes the Physical Turing Test: after a long day at work, you press a button, lay back, and couldn't tell if a neural net or a human drove you home.

Despite knowing exactly how robot learning works, I still find it magical watching the steering wheel turn by itself. 

First it feels surreal, next it becomes routine. Then, like the smartphone, taking it away actively hurts. This is how humanity gets rewired and glued to god-like technologies."}}}, "quotedRefResult": {"result": {"__typename": "Tweet", "rest_id": "2002843697273262468"}}, "rest_id": "2003593613918531891", "source": "<a href="https://mobile.twitter.com" rel="nofollow">Twitter Web App</a>", "unmention_data": {}, "views": {"count": "10979960", "state": "EnabledWithCount"}}}, "rest_id": "2003732334420590792", "source": "<a href="http://twitter.com/download/iphone" rel="nofollow">Twitter for iPhone</a>", "unmention_data": {}, "views": {"count": "9702647", "state": "EnabledWithCount"}}

